import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';

interface Audiencia {
  id: number;
  data: string;
  hora: string;
  status: string;
  vara: {
    id: number;
    nome: string;
  };
  juiz: {
    id: number;
    nome: string;
  };
  promotor: {
    id: number;
    nome: string;
  };
  processo: string;
  sala: string;
}

const ListaAudiencias: React.FC = () => {
  const [audiencias, setAudiencias] = useState<Audiencia[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [filtro, setFiltro] = useState<string>('');
  const [dataFiltro, setDataFiltro] = useState<string>('');

  useEffect(() => {
    const fetchAudiencias = async () => {
      try {
        setLoading(true);
        const response = await axios.get<Audiencia[]>('/api/audiencias');
        setAudiencias(response.data);
        setError(null);
      } catch (err) {
        setError('Erro ao carregar audiências. Por favor, tente novamente.');
        console.error('Erro ao buscar audiências:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchAudiencias();
  }, []);

  const formatarData = (data: string): string => {
    try {
      return format(new Date(data), 'dd/MM/yyyy', { locale: ptBR });
    } catch (error) {
      return data;
    }
  };

  const audienciasFiltradas = audiencias.filter(audiencia => {
    const termoBusca = filtro.toLowerCase();
    const dataFormatada = formatarData(audiencia.data);

    const correspondeAoFiltro = 
      audiencia.processo.toLowerCase().includes(termoBusca) ||
      audiencia.vara.nome.toLowerCase().includes(termoBusca) ||
      audiencia.juiz.nome.toLowerCase().includes(termoBusca) ||
      audiencia.promotor.nome.toLowerCase().includes(termoBusca) ||
      audiencia.sala.toLowerCase().includes(termoBusca) ||
      audiencia.status.toLowerCase().includes(termoBusca);

    const correspondeAData = dataFiltro ? dataFormatada === dataFiltro : true;

    return correspondeAoFiltro && correspondeAData;
  });

  const getStatusBadgeClass = (status: string): string => {
    switch (status.toLowerCase()) {
      case 'agendada':
        return 'bg-blue-100 text-blue-800';
      case 'realizada':
        return 'bg-green-100 text-green-800';
      case 'cancelada':
        return 'bg-red-100 text-red-800';
      case 'adiada':
        return 'bg-yellow-100 text-yellow-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-900"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded relative" role="alert">
        <strong className="font-bold">Erro!</strong>
        <span className="block sm:inline"> {error}</span>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold text-gray-800">Audiências</h1>
        <Link 
          to="/audiencias/nova" 
          className="bg-blue-900 hover:bg-blue-800 text-white font-bold py-2 px-4 rounded"
        >
          Nova Audiência
        </Link>
      </div>

      <div className="mb-6 flex flex-col md:flex-row gap-4">
        <div className="flex-1">
          <input
            type="text"
            placeholder="Buscar por processo, vara, juiz..."
            className="w-full px-4 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            value={filtro}
            onChange={(e) => setFiltro(e.target.value)}
          />
        </div>
        <div className="md:w-64">
          <input
            type="date"
            className="w-full px-4 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            value={dataFiltro}
            onChange={(e) => setDataFiltro(e.target.value ? format(new Date(e.target.value), 'dd/MM/yyyy', { locale: ptBR }) : '')}
          />
        </div>
      </div>

      {audienciasFiltradas.length === 0 ? (
        <div className="bg-gray-50 p-6 rounded-lg text-center">
          <p className="text-gray-600">Nenhuma audiência encontrada.</p>
        </div>
      ) : (
        <div className="overflow-x-auto">
          <table className="min-w-full bg-white border border-gray-200 rounded-lg overflow-hidden">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Processo</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Data</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Hora</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Vara</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Juiz</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
              {audienciasFiltradas.map((audiencia) => (
                <tr key={audiencia.id} className="hover:bg-gray-50">
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">{audiencia.processo}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{formatarData(audiencia.data)}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{audiencia.hora}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{audiencia.vara.nome}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{audiencia.juiz.nome}</td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${getStatusBadgeClass(audiencia.status)}`}>
                      {audiencia.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                    <div className="flex space-x-2">
                      <Link to={`/audiencias/${audiencia.id}`} className="text-blue-600 hover:text-blue-900">
                        Detalhes
                      </Link>
                      <Link to={`/audiencias/editar/${audiencia.id}`} className="text-indigo-600 hover:text-indigo-900">
                        Editar
                      </Link>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default ListaAudiencias;
